import { PineconeStore } from "langchain/vectorstores/pinecone";
import { OpenAIEmbeddings } from "langchain/embeddings/openai";

const embeddings = new OpenAIEmbeddings();
const vectorStore = await PineconeStore.fromExistingIndex(embeddings, {
  pineconeIndex: pineconeIndex,
  namespace: "rag-docs",
});

const retriever = vectorStore.asRetriever({ k: 5 });

const promptTemplate = `Use the following context to answer the question. Cite sources using [source_id].

Context: {context}

Question: {question}
Answer: `;

const qaPrompt = ChatPromptTemplate.fromPromptMessages([
  ["system", promptTemplate],
  ["human", "{question}"],
  ["placeholder", "{context}"],
]);

function extractCitations(response: string, sources: Document[]) {
  const citations = [];
  const citationRegex = /\[(\d+)\]/g;
  let match;
  while ((match = citationRegex.exec(response)) !== null) {
    const sourceId = parseInt(match[1]);
    if (sources[sourceId]) {
      citations.push({
        id: sourceId,
        content: sources[sourceId].pageContent.slice(0, 200),
        metadata: sources[sourceId].metadata,
      });
    }
  }
  return citations;
}

