import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'flowise-rag-pipeline',
});

// Flowise server config (flowise/config.ts)
export const flowiseConfig = {
  callbacks: [
    {
      type: 'afterChainExecute',
      callback: async (output: any) => {
        await vex.verify({
          type: 'rag_retrieval_relevance',
          input: output.input,
          retrieved_docs: output.sourceDocuments,
          threshold: 0.7,
        });
      },
    },
  ],
};

import { VexRAGVerifier } from '@vex_dev/sdk/rag';

const ragVerifier = new VexRAGVerifier(vex);

// In Flowise custom node or chain callback
const verifyRetrieval = async (query: string, docs: Document[]) => {
  const results = await ragVerifier.verifyRetrieval({
    query,
    documents: docs.map(d => d.pageContent),
    checks: ['semantic_similarity', 'keyword_overlap'],
    min_relevance: 0.75,
  });

  if (!results.passed) {
    throw new Error(`Low relevance docs: ${JSON.stringify(results.scores)}`);
  }

  return docs.filter((_, i) => results.passed_docs.includes(i));
};

const faithfulnessCheck = async (response: string, context: string[], citations: any[]) => {
  const result = await vex.verify({
    type: 'rag_source_faithfulness',
    response,
    context: context.join('\n'),
    expected_citations: citations,
    hallucination_threshold: 0.1,
  });

  if (!result.passed) {
    return {
      response: 'Unable to verify response against sources. Please refine query.',
      citations: [],
      vex_score: result.score,
    };
  }

  return { response, citations, vex_score: result.score };
};
